var iterations = $.steps.searchLoop.response.iterations || [];
var keywords = $.steps.parseKeywords.output.keywords;
var domain = $.input.domain.toLowerCase().replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/$/, '');
var rankingData = [];
iterations.forEach(function(iter, ki) {
  var kw = keywords[ki] || 'unknown';
  var results = (iter.searchKeyword && iter.searchKeyword.response && iter.searchKeyword.response.results) ? iter.searchKeyword.response.results : [];
  var position = -1;
  var competitors = [];
  results.forEach(function(r, idx) {
    var url = (r.url || '').toLowerCase();
    if (url.indexOf(domain) !== -1 && position === -1) {
      position = idx + 1;
    }
    competitors.push({ rank: idx + 1, title: (r.title || '').slice(0, 80), url: r.url, snippet: (r.text || '').slice(0, 100) });
  });
  rankingData.push({ keyword: kw, position: position === -1 ? 'Not found' : position, totalResults: results.length, topCompetitors: competitors.slice(0, 5) });
});
var summary = rankingData.map(function(r) { return r.keyword + ': Position ' + r.position; }).join('\n');
return { rankingData: rankingData, summary: summary, domain: domain };

var data = $.steps.compileRankingData.output;
var rankDetails = '';
data.rankingData.forEach(function(r) {
  rankDetails += 'KEYWORD: ' + r.keyword + '
POSITION: ' + r.position + '
TOP COMPETITORS:
';
  r.topCompetitors.forEach(function(c) {
    rankDetails += '  ' + c.rank + '. ' + c.title + ' (' + c.url + ')
';
  });
  rankDetails += '
';
});
var prompt = 'You are an SEO analyst. Analyze the following keyword ranking data for the domain "' + data.domain + '".

RANKING DATA:
' + rankDetails + '
Provide:
1. Assessment of current positions
2. Keywords where the domain ranks well vs poorly
3. Top competitors appearing frequently
4. Actionable recommendations to improve rankings
5. Content gaps to target

Return ONLY valid JSON:
{
  "overallScore": 0,
  "analysis": [{"keyword": "...", "position": "...", "assessment": "...", "recommendation": "..."}],
  "topCompetitors": ["domain1.com", "domain2.com"],
  "contentGaps": ["gap1", "gap2"],
  "priorityActions": ["action1", "action2"]
}';
return { prompt };

let raw = $.steps.aiAnalyze.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var rankings = $.steps.compileRankingData.output.rankingData;
var now = new Date().toISOString().split('T')[0];
var sheetData = rankings.map(function(r) {
  var aiEntry = (ai.analysis || []).find(function(a) { return a.keyword === r.keyword; });
  return {
    date: now,
    keyword: r.keyword,
    position: String(r.position),
    assessment: aiEntry ? aiEntry.assessment : '',
    recommendation: aiEntry ? aiEntry.recommendation : '',
    topCompetitor: r.topCompetitors.length > 0 ? r.topCompetitors[0].url : ''
  };
});
return { sheetData: sheetData };
